async fn sandbox_grep_via_registry_dispatches_through_bridge() {
    use {
        crate::{
            exec::ExecResult,
            fs::sandbox_bridge::test_helpers::MockSandbox,
            sandbox::{Sandbox, SandboxConfig, SandboxRouter},
        },
        std::sync::Arc,
    };

    let mock = MockSandbox::new(vec![ExecResult {
